def _load_summary(path: Path) -> tuple[np.ndarray, np.ndarray]:
    with open(path, "r") as f:
        data = json.load(f)

    config = data.get("config")
    if config is None:
        raise SystemExit("Summary JSON missing embedded result/config data")

    result = config.get("result") if isinstance(config, dict) else data
    if "result" in data:
        result = data["result"]

    C_geo = np.asarray(result["C_geo_values"], dtype=float)
    ds_plateau = np.asarray(result["ds_plateau"], dtype=float)
    return C_geo, ds_plateau


def _split_intervals(C_geo: np.ndarray, counts: np.ndarray) -> list[dict]:
    intervals: list[dict] = []
    for i in range(len(counts) - 1):
        delta = counts[i + 1] - counts[i]
        if delta > 0:
            intervals.append({
                "index": i,
                "from_N": int(round(counts[i])),
                "to_N": int(round(counts[i + 1])),
                "C_lo": float(C_geo[i]),
                "C_hi": float(C_geo[i + 1]),
                "C_mid": float((C_geo[i] + C_geo[i + 1]) / 2.0),
                "delta_N": float(delta),
            })
    return intervals


def _attach_interval_signature(peak_idx: int, C_peak: float, intervals: list[dict]):
    if not intervals:
        return None
    best = None
    best_err = None
    for interval in intervals:
        err = abs(C_peak - interval["C_mid"])
        if best is None or err < best_err:
            best = interval
            best_err = err
    return best


def _top_k_peaks(split_rate: np.ndarray, k: int = 2) -> list[int]:
    if split_rate.size == 0:
        return []
    finite_idx = np.where(np.isfinite(split_rate))[0]
    if finite_idx.size == 0:
        finite_idx = np.arange(split_rate.size)
    order = finite_idx[np.argsort(split_rate[finite_idx])[::-1]]
    seen = []
    for idx in order:
        if len(seen) >= k:
            break
        seen.append(int(idx))
    return seen


def _format_interval_signature(interval: dict | None) -> str:
    if not interval:
